# Matplotlib and pandas are required to run this script.
from matplotlib import pyplot, ticker
import pandas
import subprocess

# Build and run the unit tests.
subprocess.run(['dotnet', 'test'], shell=True)

# Get the CSV generated by the unit tests.
results = pandas.read_csv('Tests/bin/Debug/net10.0/Results.csv')

# Get the success rates for each device category.
success_rates = [results['Keyboard Success Rate'][0],
                 results['Mouse Success Rate'][0]]

# Plot the results on a bar graph.
pyplot.bar(['Keyboard', 'Mouse'], success_rates)
pyplot.gca().yaxis.set_major_formatter(ticker.PercentFormatter(xmax=1.0))
pyplot.title('Input Processing Component Accuracy by Input Device')
pyplot.xlabel('Input Device')
pyplot.ylabel('Accuracy')
pyplot.show()
